import React, { createContext, useState, useContext, useEffect } from 'react';
import { ROLES } from '../utils/helpers';

// 1. Export trực tiếp AuthContext để các file dùng useContext(AuthContext) hoạt động
export const AuthContext = createContext();

// 2. Export Hook useAuth để các file cũ dùng useAuth() hoạt động
export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  // Giả lập user để test, mặc định chưa login
  const [user, setUser] = useState(() => {
    const savedUser = localStorage.getItem('user');
    return savedUser ? JSON.parse(savedUser) : null;
  });

  const login = (username, role) => {
    // Logic login giả lập
    const userData = { 
        id: 1, // Mock ID
        username, 
        role, 
        name: username // Mock name
    };
    setUser(userData);
    localStorage.setItem('user', JSON.stringify(userData));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};
